// Evaluate SSL-Checker.io response and set alert fields
const item = $input.first();
const result = item.json;

const certValid = result.result?.cert_valid === 'true' || result.result?.cert_valid === true;
const daysLeft = parseInt(result.result?.days_until_expiry ?? result.result?.cert_exp_days ?? '999', 10);
const domain = result.host || result.domain || '';
const originalUrl = result.host || domain;
const checkDate = new Date().toISOString().split('T')[0];

let alertLevel = 'OK';
let needsAlert = false;
let alertMessage = '';

if (!certValid) {
  alertLevel = 'CRITICAL';
  needsAlert = true;
  alertMessage = 'Certificate is invalid or could not be verified.';
} else if (daysLeft <= 7) {
  alertLevel = 'CRITICAL';
  needsAlert = true;
  alertMessage = `Certificate expires in ${daysLeft} day(s). Immediate renewal required.`;
} else if (daysLeft <= 30) {
  alertLevel = 'WARNING';
  needsAlert = true;
  alertMessage = `Certificate expires in ${daysLeft} day(s). Schedule renewal soon.`;
} else if (daysLeft <= 60) {
  alertLevel = 'NOTICE';
  needsAlert = false;
  alertMessage = `Certificate expires in ${daysLeft} day(s). No immediate action needed.`;
} else {
  alertLevel = 'OK';
  needsAlert = false;
  alertMessage = `Certificate valid for ${daysLeft} more day(s).`;
}

return [{
  json: {
    domain,
    originalUrl,
    certValid,
    daysLeft,
    alertLevel,
    alertMessage,
    needsAlert,
    checkDate,
    result: result.result || {}
  }
}];

