// Log all SSL check results for monitoring
const items = $input.all();
const logData = [];

for (const item of items) {
  const data = item.json;

  logData.push({
    timestamp: new Date().toISOString(),
    domain: data.domain,
    originalUrl: data.originalUrl,
    alertLevel: data.alertLevel,
    alertMessage: data.alertMessage,
    daysLeft: data.daysLeft,
    isValid: data.certValid,
    needsAlert: data.needsAlert
  });
}

console.log('SSL Certificate Check Results:', JSON.stringify(logData, null, 2));

return items;
